interface Props {
  salesByState: Record<string, { count: number; revenue: number }>;
}

const BrazilMap = memo(function BrazilMap({ salesByState }: Props) {
  const maxCount = useMemo(() => {
    const counts = Object.values(salesByState).map((s) => s.count);
    return Math.max(...counts, 1);
  }, [salesByState]);

  const getColor = (count: number) => {
    if (count === 0) return "hsl(var(--secondary))";
    const intensity = Math.min(count / maxCount, 1);
    const lightness = 50 - intensity * 25;
    const saturation = 50 + intensity * 50;
    return `hsl(151, ${saturation}%, ${lightness}%)`;
  };

  const fmt = (v: number) => `R$ ${v.toFixed(2).replace(".", ",")}`;

  return (
    <div className="w-full aspect-[1.1] relative">
      <svg viewBox="0 10 590 520" className="w-full h-full" style={{ filter: "drop-shadow(0 2px 8px hsl(var(--primary) / 0.15))" }}>
        <defs>
          <filter id="glow">
            <feGaussianBlur stdDeviation="2" result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>
        {Object.entries(STATES).map(([uf, state]) => {
          const data = salesByState[uf] || { count: 0, revenue: 0 };
          const hasData = data.count > 0;
          return (
            <Tooltip key={uf}>
              <TooltipTrigger asChild>
                <g
                  className="cursor-pointer transition-all duration-300"
                  style={{ filter: hasData ? "url(#glow)" : "none" }}
                >
                  <path
                    d={state.path}
                    fill={getColor(data.count)}
                    stroke="hsl(var(--background))"
                    strokeWidth="0.8"
                    className="transition-colors duration-300 hover:brightness-125 hover:stroke-primary"
                    strokeLinejoin="round"
                  />
                  {/* Only show labels for larger states */}
                  {!["DF", "SE", "AL"].includes(uf) && (
                    <text
                      x={state.cx}
                      y={state.cy}
                      textAnchor="middle"
                      dominantBaseline="central"
                      className="fill-foreground font-bold pointer-events-none select-none"
                      style={{ fontSize: 7, opacity: 0.85 }}
                    >
                      {uf}
                    </text>
                  )}
                </g>
              </TooltipTrigger>
              <TooltipContent side="top" className="bg-card border-border shadow-xl">
                <div className="text-sm">
                  <p className="font-bold text-foreground">{state.name} ({uf})</p>
                  <p className="text-muted-foreground">
                    {data.count} venda{data.count !== 1 ? "s" : ""} · {fmt(data.revenue)}
                  </p>
                </div>
              </TooltipContent>
            </Tooltip>
          );
        })}
      </svg>
    </div>
  );
});

export default BrazilMap;
